  ('heelevel3-6f0ba476-moex-00498', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-f6c431ec', 'sub-heelevel3-6f0ba476-04', NULL, 'essay', '為因應民意期待公權力能夠更有效抑制酒後駕車的行為，政府考慮以下
兩種政策方向：
強化取締：維持目前查獲酒駕行為之罰金，但加強取締使查獲酒駕行
為之機率提高一倍，自 10%提升至 20%；
提高罰金：維持目前取締強度，但將查獲酒駕行為之罰金提高一倍，
自 100,000 元提升至 200,000元。
請分別就酒後駕車者偏好為風險厭惡與風險喜好兩種情形，討論強化
取締與提高罰金，何種政策方向對於抑制酒駕會有更好的效果？請繪
製圖形，並佐以文字說明詳細解釋。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "44c10a6685c9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "財政學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
